1	// game-of-life.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { nextGeneration } from "./game-of-life.js";
4	
5	describe("Game of Life - Next Generation", () => {
6	  it("should return empty array for a single live cell (underpopulation)", () => {
7	    expect(nextGeneration([[0, 0]])).toEqual([]);
8	  });
9	  it("should return empty array for two adjacent cells, each with one neighbor (underpopulation)", () => {
10	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
11	  });
12	  it("should keep alive a cell with three live neighbors (survival)", () => {
13	    // ###
14	    // .#.   the focal cell (1,1) has 3 live neighbors -> it survives
15	    expect(nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1]])).toContainEqual([1, 1]);
16	  });
17	  it("should kill a live cell with more than three live neighbors (overpopulation)", () => {
18	    // ###
19	    // .#.   the focal cell (1,1) has 4 live neighbors -> it dies
20	    // ###
21	    expect(nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1], [0, 2], [1, 2], [2, 2]])).not.toContainEqual([1, 1]);
22	  });
23	  it("should bring to life a dead cell with exactly three live neighbors (reproduction)", () => {
24	    // ##.      ##.
25	    // #..  ->  ##.   the dead cell (1,1) has 3 live neighbors -> it is born
26	    expect(nextGeneration([[0, 0], [1, 0], [0, 1]])).toContainEqual([1, 1]);
27	  });
28	  it.todo("should keep a block still life unchanged");
29	  it.todo("should rotate a vertical blinker into a horizontal blinker including negative coordinates");
30	});
31

1	export type Cell = [number, number];
2	
3	const isSameCell = ([x, y]: Cell, [otherX, otherY]: Cell): boolean =>
4	  x === otherX && y === otherY;
5	
6	const containsCell = (cells: Cell[], cell: Cell): boolean =>
7	  cells.some((other) => isSameCell(other, cell));
8	
9	const NEIGHBOR_OFFSETS: Cell[] = [
10	  [-1, -1], [-1, 0], [-1, 1],
11	  [0, -1], [0, 1],
12	  [1, -1], [1, 0], [1, 1],
13	];
14	
15	const neighborsOf = ([x, y]: Cell): Cell[] =>
16	  NEIGHBOR_OFFSETS.map(([dx, dy]): Cell => [x + dx, y + dy]);
17	
18	const deduplicate = (cells: Cell[]): Cell[] =>
19	  cells.filter((cell, index) => !containsCell(cells.slice(0, index), cell));
20	
21	const countLiveNeighbors = (cell: Cell, liveCells: Cell[]): number =>
22	  neighborsOf(cell).filter((neighbor) => containsCell(liveCells, neighbor))
23	    .length;
24	
25	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
26	  const survivors = liveCells.filter(
27	    (cell) => countLiveNeighbors(cell, liveCells) === 3,
28	  );
29	  const births = deduplicate(liveCells.flatMap(neighborsOf)).filter(
30	    (cell) =>
31	      !containsCell(liveCells, cell) &&
32	      countLiveNeighbors(cell, liveCells) === 3,
33	  );
34	  return [...survivors, ...births];
35	};
